public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);
public record ReactionEventArgs(int MessageId, string Emoji);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_7f9a996de4d740b1ae439102b4dccfa2.Services

<div class="message-bubble @(isHovered ? "hovered" : "")"
     @onmouseenter="() => isHovered = true"
     @onmouseleave="OnMouseLeave">

    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>

    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge"
                        @onclick="() => OnReact.InvokeAsync(new ReactionEventArgs(Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadInfo is not null)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadInfo.ReplyCount replies · last reply @FormatRelativeTime(ThreadInfo.LastReplyAt)
        </button>
    }

    @if (isHovered)
    {
        <div class="message-actions">
            <button @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">💬</button>
            <button @onclick="ToggleEmojiPicker" title="Add reaction">😀</button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in CommonEmojis)
            {
                <button @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadInfo { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<ReactionEventArgs> OnReact { get; set; }

    private bool isHovered;
    private bool showEmojiPicker;

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void OnMouseLeave()
    {
        isHovered = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync(new ReactionEventArgs(Message.Id, emoji));
    }

