toolArgs.file_text:
.message-bubble {
    position: relative;
    padding: 8px 12px;
    border-radius: 6px;
    transition: background-color 0.15s;
}

.message-bubble.hovered {
    background-color: rgba(0, 0, 0, 0.04);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.93rem;
    line-height: 1.5;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #ddd;
    border-radius: 12px;
    background: #f0f0f0;
    font-size: 0.82rem;
    cursor: pointer;
}

.reaction-badge:hover {
    background: #e0e0e0;
    border-color: #bbb;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 2px 6px;
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.82rem;
    cursor: pointer;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 8px;
    display: flex;
    gap: 2px;
    padding: 2px 4px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
}

.message-actions button {
    background: none;
    border: none;
    padding: 4px 6px;
    cursor: pointer;
    font-size: 1rem;
    border-radius: 4px;
}

.message-actions button:hover {
    background: #f0f0f0;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    padding: 6px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    margin-top: 4px;
    width: fit-content;
}

.emoji-picker button {
    background: none;
    border: none;
    padding: 4px 8px;
    cursor: pointer;
    font-size: 1.2rem;
    border-radius: 4px;
}

.emoji-picker button:hover {
    background: #f0f0f0;
}

