toolArgs.file_text:
@using sv_7f9a996de4d740b1ae439102b4dccfa2.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageBubble Message="RootMessage" OnReact="OnReact" />
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <MessageBubble Message="reply" OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonText="Reply"
                      OnSend="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<ReactionEventArgs> OnReact { get; set; }
}

.thread-panel {
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #ddd;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root {
    padding: 8px 16px;
    border-bottom: 1px solid #e8e8e8;
    background: #fafafa;
}

.thread-divider {
    padding: 6px 16px;
    font-size: 0.78rem;
    color: #888;
    border-bottom: 1px solid #e8e8e8;
    font-weight: 600;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 16px;
}

