@page "/chat"
@using sv_7f9a996de4d740b1ae439102b4dccfa2.Services
@using sv_7f9a996de4d740b1ae439102b4dccfa2.Components.Chat
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="sidebar-panel">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-panel @(threadOpen ? "" : "expanded")">
        @if (activeChannel is not null)
        {
            <div class="channel-header">
                <h2># @activeChannel.Name</h2>
                <p>@activeChannel.Description</p>
            </div>

            <div class="message-list" @ref="messageListRef">
                <div @ref="scrollSentinel" class="scroll-sentinel"></div>

                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }

                @foreach (var msg in messages)
                {
                    <MessageBubble Message="msg"
                                   ThreadInfo="GetThreadInfo(msg.Id)"
                                   OnOpenThread="OpenThread"
                                   OnReact="HandleReaction" />
                }
            </div>

            <MessageInput OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadOpen)
    {
        <div class="thread-panel-container">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Channel? activeChannel;
    private int activeChannelId;

    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;

    private ElementReference messageListRef;
    private ElementReference scrollSentinel;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<Chat>? dotNetRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
            dotNetRef = DotNetObjectReference.Create(this);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        if (activeChannelId == channelId) return;

        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadSummaries.Clear();
        hasMoreMessages = true;
        CloseThread();

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        hasMoreMessages = messages.Count == PageSize;
        ComputeThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);

        // Clear unread badge locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }

        StateHasChanged();

        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
            await jsModule.InvokeVoidAsync("observeScrollSentinel", scrollSentinel, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        hasMoreMessages = older.Count == PageSize;
        messages.InsertRange(0, older);
        ComputeThreadSummaries();

        isLoadingMore = false;
        StateHasChanged();
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(msg);
        StateHasChanged();

        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
        }
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(messageId);
        threadOpen = true;

        if (threadReplies.Count > 0)
        {
            threadSummaries[messageId] = new ThreadSummary(
                messageId, threadReplies.Count, threadReplies[^1].SentAt);
        }
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            activeChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id, threadReplies.Count, reply.SentAt);
    }

    private async Task HandleReaction(ReactionEventArgs args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        UpdateReactionLocally(messages, args);
        UpdateReactionLocally(threadReplies, args);
    }

    private static void UpdateReactionLocally(List<Message> messageList, ReactionEventArgs args)
    {
        var msg = messageList.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is null) return;

        var reaction = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
        if (reaction is not null)
        {
            if (!reaction.Users.Contains("You"))
                reaction.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
        }
    }

    private ThreadSummary? GetThreadInfo(int messageId) =>
        threadSummaries.GetValueOrDefault(messageId);

    private void ComputeThreadSummaries()
    {
        var replies = messages.Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);
        foreach (var group in replies)
        {
            var sorted = group.OrderBy(m => m.SentAt).ToList();
            threadSummaries.TryAdd(group.Key,
                new ThreadSummary(group.Key, sorted.Count, sorted[^1].SentAt));
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("dispose");
                await jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit already gone — safe to ignore
            }
        }
        dotNetRef?.Dispose();
    }
}

