.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.sidebar-panel {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.main-panel {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.main-panel.expanded {
    flex: 1;
}

.thread-panel-container {
    width: 25%;
    min-width: 280px;
    max-width: 420px;
    flex-shrink: 0;
}

.channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
}

.channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-header p {
    margin: 2px 0 0;
    font-size: 0.82rem;
    color: #666;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 20px;
}

.scroll-sentinel {
    height: 1px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 0.85rem;
    color: #888;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #888;
    font-size: 1.1rem;
}

